sys_script_include.script:
var PulseCategoryAjax = Class.create();
PulseCategoryAjax.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

    getCategories: function () {
        var tableName = this.getParameter('sysparm_table');
        if (!tableName)
            return '[]';

        var result = [];

        var gr = new GlideRecord('sys_choice');
        gr.addQuery('inactive', false);
        gr.addQuery('name', tableName);
        gr.addQuery('element', 'category');
        gr.orderBy('label');
        gr.query();

        while (gr.next()) {
            result.push({
                value: gr.getValue('value'),
                label: gr.getValue('label')
            });
        }

        return new global.JSON().encode(result);
    },

	getSubCategories: function () {
    var tableName = (this.getParameter('sysparm_table') || '').toString();
    var categoryLabel = (this.getParameter('sysparm_category') || '').toString();

    if (!tableName || !categoryLabel)
        return '[]';

    var result = [];
    var gr = new GlideRecord('sys_choice');
    gr.addQuery('inactive', false);
    gr.addQuery('name', tableName);
    gr.addQuery('element', 'subcategory');
    gr.addQuery('dependent_value', categoryLabel); // <-- "Database"
    gr.orderBy('label');
    gr.query();

    while (gr.next()) {
        result.push({
            value: gr.getValue('value'),
            label: gr.getValue('label')
        });
    }

    return new global.JSON().encode(result);
},

getStates: function () {
    var tableName = (this.getParameter('sysparm_table') || '').toString();
    if (!tableName)
        return '[]';

    var element = 'state';

    // Table-specific overrides
    if (tableName === 'sc_request')
        element = 'request_state';
    else if (tableName === 'sc_req_item')
        element = 'stage';

    var result = [];

    var gr = new GlideRecord('sys_choice');
    gr.addQuery('inactive', false);
    gr.addQuery('name', tableName);
    gr.addQuery('element', element);
    gr.orderBy('sequence');
    gr.orderBy('label');
    gr.query();

    while (gr.next()) {
        result.push({
            value: gr.getValue('value'),
            label: gr.getValue('label')
        });
    }

    return new global.JSON().encode(result);
},


getCloseCodes: function () {
    var tableName = (this.getParameter('sysparm_table') || '').toString();
    if (!tableName)
        return '[]';

    // Default behaviour
    var element = 'close_code';

    // Special case: Requests should map “closure” using status
    if (tableName === 'sc_request')
        element = 'request_state';

    // Optional: if you also want RITMs to map “closure” using stage
    // else if (tableName === 'sc_req_item')
    //     element = 'stage';

    var result = [];

    var gr = new GlideRecord('sys_choice');
    gr.addQuery('inactive', false);
    gr.addQuery('name', tableName);
    gr.addQuery('element', element);
    gr.orderBy('sequence');
    gr.orderBy('label');
    gr.query();

    while (gr.next()) {
        result.push({
            value: gr.getValue('value'),
            label: gr.getValue('label')
        });
    }

    return new global.JSON().encode(result);
},

getPriorities: function () {
    var result = [];

    var gr = new GlideRecord('sys_choice');
    gr.addQuery('inactive', false);
    gr.addQuery('name', 'task');
    gr.addQuery('element', 'priority');
    gr.orderBy('sequence');
    gr.orderBy('label');
    gr.query();

    while (gr.next()) {
        result.push({
            value: gr.getValue('value'),
            label: gr.getValue('label')
        });
    }

    return new global.JSON().encode(result);
},

    type: 'PulseCategoryAjax'
});
